import csv
import sys
import re
from datetime import datetime

def normalize_date(date_str):
    date_str = date_str.strip()
    formats = ['%m/%d/%Y', '%Y-%m-%d', '%d-%b-%Y']
    for fmt in formats:
        try:
            return datetime.strptime(date_str, fmt).strftime('%Y-%m-%d')
        except ValueError:
            continue
    return date_str

def normalize_phone(phone_str):
    # Strip all non-numeric characters
    nums = re.sub(r'\D', '', phone_str)
    # Handle US numbers (assuming 10 digits or 11 with leading 1)
    if len(nums) == 10:
        return f"+1{nums}"
    elif len(nums) == 11 and nums.startswith('1'):
        return f"+{nums}"
    return phone_str # Return original if it doesn't fit standard US pattern

def normalize_currency(curr_str):
    # Remove $ and commas
    clean = re.sub(r'[$,]', '', curr_str).strip()
    try:
        return str(float(clean))
    except ValueError:
        return clean

def main():
    if len(sys.argv) != 3:
        print("Usage: python csv_normalizer.py <input_path> <output_path>")
        sys.exit(1)

    input_path = sys.argv[1]
    output_path = sys.argv[2]

    cells_changed = 0

    try:
        with open(input_path, mode='r', newline='', encoding='utf-8') as infile:
            reader = csv.reader(infile)
            header = next(reader)

            # Identify columns based on header names (case-insensitive)
            col_map = {name.strip().lower(): i for i, name in enumerate(header)}

            rows = []
            for row in reader:
                new_row = []
                for i, cell in enumerate(row):
                    original = cell
                    # Always strip whitespace
                    val = cell.strip()

                    # Apply specific normalization based on header
                    col_name = header[i].strip().lower()
                    if 'date' in col_name:
                        val = normalize_date(val)
                    elif 'phone' in col_name:
                        val = normalize_phone(val)
                    elif 'amount' in col_name or 'currency' in col_name:
                        val = normalize_currency(val)

                    if val != original:
                        cells_changed += 1
                    new_row.append(val)
                rows.append(new_row)

        with open(output_path, mode='w', newline='', encoding='utf-8') as outfile:
            writer = csv.writer(outfile)
            writer.writerow([h.strip() for h in header])
            writer.writerows(rows)

        print(f"CellsChanged: {cells_changed}")

    except Exception as e:
        print(f"Error: {e}")
        sys.exit(1)

if __name__ == "__main__":
    main()

